# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.{Actor, Props}

final case class Deposit(amount: BigDecimal)
final case class Withdraw(amount: BigDecimal)
case object GetBalance

class AccountActor(initialBalance: BigDecimal) extends Actor {
  private var balance: BigDecimal = initialBalance

  override def receive: Receive = {
    case Deposit(amount) =>
      balance += amount
      sender() ! balance

    case Withdraw(amount) =>
      if (amount <= balance) {
        balance -= amount
        sender() ! Right(balance)
      } else {
        sender() ! Left("Insufficient funds")
      }

    case GetBalance =>
      sender() ! balance
  }
}

object AccountActor {
  def props(initialBalance: BigDecimal): Props = Props(new AccountActor(initialBalance))
}